firmware_template.source:
#include "sgp30.h"
#include <Wire.h>
#include <Adafruit_SGP30.h>
static Adafruit_SGP30 sgp;
static uint16_t _tvoc=0,_eco2=0;
static unsigned long _last=0;
void sgp30_setup(){Wire.begin();if(!sgp.begin()){Serial.println("[sgp30] Fail!");return;}Serial.println("[sgp30] OK");}
void sgp30_loop(){if(millis()-_last<1000)return;_last=millis();if(sgp.IAQmeasure()){_tvoc=sgp.TVOC;_eco2=sgp.eCO2;}}
uint16_t sgp30_get_tvoc(){return _tvoc;}
uint16_t sgp30_get_eco2(){return _eco2;}
